  handling_method_en = VALUES(handling_method_en),
  exception_allowed = VALUES(exception_allowed),
  pdf_deeplink = VALUES(pdf_deeplink),
  version_status = VALUES(version_status);

UPDATE rule_catalog
SET version_status = 'ACTIVE',
    phase_code = 'PHASE_3',
    active_flag = TRUE,
    description_zh = CONCAT(description_zh, ' 当前已接入基础规则评估。'),
    description_en = CONCAT(description_en, ' Basic evaluation is currently enabled.')
WHERE rule_id IN ('RG-TIME-008', 'RG-FDP-003', 'RG-FDP-007', 'RG-BASE-008', 'RG-STBY-002');
